employment"},{"title":"Sample resume / CV (mock)","description":"Skilled migration format — chronological roles and NOC alignment.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample nomination / job offer letter (mock)","description":"PNP nomination or employer-backed offer where applicable.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample bank statement (mock)","description":"6-month statement with name, account number, and closing balance — explain seasoning.","mimeType":"application/pdf","docKind":"financial"}],"navBucket":"immigration","workingRights":{"applicant":{"summary":"Employer-specific or open work permits authorize work per conditions on the permit (employer, occupation, location, expiry).","details":["LMIA-exempt streams (IEC, PGWP, BOWP, IEC, intra-company) have specific rules.","PR applicants with maintained status may qualify for BOWP."],"restrictions":["Working outside permit conditions is unauthorized employment"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada.html","lastVerified":"Jun 2026"},"spouse":{"summary":"Spouse/partner of skilled worker or PR applicant often eligible for open work permit (SOWP) during processing or after PR stage.","details":["PNP nominations may include employment restrictions affecting open permits — verify nomination letter."],"restrictions":[],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","lastVerified":"Jun 2026"}},"fullCostBreakdown":{"title":"Full cost breakdown — Canada – Temporary Resident to PR Pathway","currency":"CAD","lastVerified":"Jun 2026","disclaimer":"Indicative costs for counselor discussions only. Government fees, tuition, and living amounts change — verify on official websites before quoting clients. Exchange rates affect INR equivalents.","sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","sections":[{"id":"fees","label":"Government & visa fees","items":[{"la