mployer change","severity":"Medium"}],"faqs":[{"q":"Can we guarantee work permit?","a":"No. Both ESDC (LMIA) and IRCC must approve where applicable."},{"q":"LMIA processing time?","a":"Varies—often 2–5 months for standard LMIA. Verify current ESDC service standards."},{"q":"LMIA-exempt categories?","a":"Includes ICT transfers, CUSMA professionals, PGWP, spousal open permits, etc.—verify exemption code."},{"q":"Can spouse work?","a":"Spouse may qualify for open work permit in some categories—verify current rules."},{"q":"Employer costs for LMIA?","a":"LMIA application fee CAD $1,000 per position; plus recruitment costs."},{"q":"Can apply at border?","a":"Some nationals may flagpole—verify eligibility and current policy."},{"q":"Work permit and PR pathway?","a":"Canadian experience may support CEC via Express Entry."},{"q":"What if LMIA refused?","a":"Review ESDC reasons; address recruitment or wage issues; reapply or explore exempt categories."},{"q":"What is Description for this service?","a":"Employer-specific or open work permit allowing foreign nationals to work in Canada. LMIA-required streams need positive LMIA from Employment and Social Development Canada (ESDC)."},{"q":"What is Eligible applicants for this service?","a":"Valid job offer from Canadian employer · LMIA or exempt category · Qualifying skills/experience · Medical/biometrics as required"},{"q":"What is LMIA process for this service?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"Important note on LMIA process?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"What is Key authority for this service?","a":"ESDC (LMIA) · IRCC (work permit)"},{"q":"What is After approval for this service?","a":"Work for specified employer (closed permit) or open category. Maintain status; employer compliance with LMIA conditions."},{"q":"Is Valid job offer / contract required?","a":"Valid job offer / contract is typically required."},{"q":"Is LMIA positive or exempt category confirmed required?","a":"Employer responsibility for LMIA"},{"q":"Is Qualifying work experience/education required?","a":"Qualifying work experience/education is typically required."},{"q":"Is Medical exam (if required) required?","a":"Assess whether Medical exam (if required) is satisfied for this case."},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No criminal inadmissibility required?","a":"No criminal inadmissibility is typically required."},{"q":"Is Employer compliance history required?","a":"Verify employer legitimacy"},{"q":"What is the Processing time?","a":"3–9m — LMIA + IRCC combined"},{"q":"What is the Government fee?","a":"CAD $155 — Worker fee + biometrics"},{"q":"What is the Our approval rate?","a":"86% — ~78% benchmark"},{"q":"What is the Required docs?","a":"15 — + LMIA if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & LMIA"},{"q":"What if the client has LMIA advertising deficiencies?","a":"Ensure ESDC advertising compliance before LMIA submit"},{"q":"Why is LMIA advertising deficiencies a problem?","a":"Employer did not meet recruitment advertising requirements."},{"q":"What if the client has Wrong NOC/ wage offer?","a":"Verify TEER and prevailing wage on Job Bank"},{"q":"Why is Wrong NOC/ wage offer a problem?","a":"Job classification or wage below median for region."}],"compliance":["Client service agreement and consent must be on file before submission","Never guarantee visa or immigration approval; use approved-language only","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Confirm LMIA vs exempt at intake","Verify employer genuine and financially stable","Align NOC/TEER with actual job duties","Track LMIA and IRCC stages separately","Medical/biometrics immediately on request"],"postApproval":["Send work permit conditions and employer name","Explain closed vs open permit rules","Guide on SIN application","Discuss CEC timeline if applicable"],"performance":{"ourRate":86,"industryRate":78,"stats":[{"label":"Files this year","value":"67"},{"label":"Approved","value":"58"},{"label":"Refused","value":"7"},{"label":"Withdrawn","value":"2"}]},"approvalFactors":[{"label":"Our rate vs industry","ours":86,"benchmark":78},{"label":"LMIA prep quality","ours":84,"benchmark":70},{"label":"NOC accuracy","ours":88,"benchmark":74},{"label":"First-submit completeness","ours":90,"benchmark":76}],"timeline":[{"weeks":"1–2","title":"Category assessment, employer verification"},{"weeks":"2–16","title":"LMIA processing (if required)"},{"weeks":"16–20","title":"IRCC work permit application"},{"weeks":"3–9m","title":"Total timeline varies"}],"relatedServices":[{"label":"Canada – Express Entry PR","libraryId":""},{"label":"Canada – PGWP","libraryId":""},{"label":"Canada – Spouse Visa","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial Canada work permit counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"Verify employer is not on IRCC non-compliant list before LMIA investment."}],"resources":[{"title":"IRCC — Work in Canada","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada.html","description":"Work permit overview"},{"title":"ESDC — LMIA","url":"https://www.canada.ca/en/employment-social-development/services/foreign-workers.html","description":"LMIA information"},{"title":"IRCC — Work permit apply","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/apply.html","description":"Application steps"},{"title":"IRCC — Processing times","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/application/check-processing-times.html","description":"Estimates"},{"title":"IRCC — LMIA exempt workers","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada/permit/temporary/work-permit-exemptions.html","description":"Exemption categories"}],"quiz":[{"level":1,"question":"What is an employer-specific work permit?","options":["A permit tied to a named employer and job conditions","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Closed permits list employment conditions such as employer, role, location, and validity."},{"level":1,"question":"What does LMIA stand for?","options":["Labour Market Impact Assessment","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"An LMIA is an ESDC assessment used in many TFWP cases."},{"level":1,"question":"Which program commonly requires an LMIA?","options":["Temporary Foreign Worker Program","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The TFWP is generally LMIA-based."},{"level":1,"question":"What is the purpose of an LMIA?","options":["To assess the labour market impact of hiring a foreign worker","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"ESDC reviews whether hiring the worker will have a positive or neutral impact."},{"level":1,"question":"What does IMP stand for?","options":["International Mobility Program","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The IMP includes LMIA-exempt work permit categories."},{"level":1,"question":"What does LMIA-exempt mean?","options":["A work permit may be issued under a specific exemption code without an LMIA","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"LMIA-exempt does not necessarily mean work-permit exempt."},{"level":1,"question":"Who usually applies for an LMIA?","options":["The Canadian employer","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employers apply to ESDC/Service Canada before the worker applies for the permit."},{"level":1,"question":"What supports a worker''s application after a positive LMIA?","options":["LMIA approval and employment offer details","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The worker uses the LMIA and offer documents to support the permit request."},{"level":1,"question":"What is an open work permit?","options":["A permit not tied to one specific employer","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Open permits allow work for most employers, subject to conditions."},{"level":1,"question":"What is a typical closed-permit condition?","options":["Work only for the employer named on the permit","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Working outside listed conditions can create compliance problems."},{"level":1,"question":"What does TFWP stand for?","options":["Temporary Foreign Worker Program","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"TFWP refers to LMIA-based temporary foreign worker hiring."},{"level":1,"question":"Who issues most work permits?","options":["Immigration, Refugees and Citizenship Canada","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"IRCC issues work permits while ESDC assesses LMIAs."},{"level":1,"question":"Who assesses most LMIA applications?","options":["Employment and Social Development Canada or Service Canada","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"ESDC/Service Canada reviews labour market factors."},{"level":1,"question":"Which category can be LMIA-exempt?","options":["Some intra-company transferees","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Certain ICT cases may qualify under IMP rules if criteria are met."},{"level":1,"question":"What is a job offer''s role?","options":["It describes the proposed employment position and conditions","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Work permit applications often rely on detailed employment terms."},{"level":1,"question":"What is the employer compliance fee linked to?","options":["Many LMIA-exempt employer-specific IMP offers","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employers often submit the offer and pay a fee through the Employer Portal."},{"level":1,"question":"Which portal is used for many LMIA-exempt offers?","options":["Employer Portal","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The Employer Portal links the offer to the worker''s application."},{"level":1,"question":"What does a foreign worker usually need before starting work?","options":["Authorization to work","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Foreign nationals generally need work authorization unless an exemption applies."},{"level":1,"question":"What is not a work permit by itself?","options":["A job offer letter","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A job offer supports an application but is not authorization to work."},{"level":1,"question":"What is a NOC code used for?","options":["Classifying job duties and skill profile","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"NOC codes help classify occupations for immigration and labour programs."},{"level":1,"question":"Which pathway is most tied to recruitment evidence?","options":["LMIA-based TFWP","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Many LMIA streams require recruitment and labour market evidence."},{"level":1,"question":"What does a positive LMIA generally indicate?","options":["Hiring is expected to have a positive or neutral labour market impact","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A positive LMIA can support an employer-specific work permit."},{"level":1,"question":"What does a negative LMIA usually mean?","options":["It cannot support the requested work permit","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A negative LMIA does not provide the needed labour market support."},{"level":1,"question":"Which worker is likely on a closed permit?","options":["A cook authorized for one named restaurant","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employer-specific permits are tied to the listed employer and role."},{"level":1,"question":"Why read printed permit conditions?","options":["They define what work is authorized","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Working outside permit conditions can affect current and future status."},{"level":2,"question":"What is usually first in an LMIA-based hiring process?","options":["The employer identifies the correct LMIA stream and recruitment requirements","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The employer must satisfy stream-specific requirements before the worker applies."},{"level":2,"question":"Why are recruitment records important for LMIAs?","options":["They show efforts to hire Canadians or permanent residents first","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Recruitment evidence is central to many labour market assessments."},{"level":2,"question":"Which wage issue is commonly assessed in LMIAs?","options":["Whether the offered wage meets prevailing wage rules","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"ESDC reviews wages for the occupation and location."},{"level":2,"question":"What does an employer submit for many IMP closed permits?","options":["An offer of employment through the Employer Portal","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Many LMIA-exempt employer-specific permits require an online employer submission."},{"level":2,"question":"Which number may the worker need from the Employer Portal?","options":["Offer of employment number","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"This number links the employer submission to the worker''s application."},{"level":2,"question":"What should be consistent across offer and application?","options":["Title, duties, wage, employer, and location","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Consistency helps officers assess the employment and category."},{"level":2,"question":"Why must the NOC match actual duties?","options":["Officers assess duties, not job title alone","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A title cannot overcome duties that do not fit the claimed NOC."},{"level":2,"question":"What is a transition plan?","options":["An employer plan to reduce reliance on foreign workers","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Some high-wage LMIA cases require transition planning."},{"level":2,"question":"What can trigger low-wage LMIA rules?","options":["Offered wage below the provincial or territorial median","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"LMIA streams often distinguish high-wage and low-wage roles by median wage."},{"level":2,"question":"What is a low-wage cap?","options":["A limit on the proportion of low-wage temporary foreign workers","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Low-wage rules can cap TFWs at a worksite."},{"level":2,"question":"Why might a medical exam be required?","options":["Occupation, residence history, or public health rules can trigger it","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Medical requirements depend on job type and personal history."},{"level":2,"question":"When should a closed-permit holder apply to change employers?","options":["Before starting work for the new employer","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Closed permits are not automatically transferable."},{"level":2,"question":"What is a port of entry letter of introduction?","options":["A letter supporting permit issuance at entry, not the permit itself","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The actual permit is issued separately when requirements are met."},{"level":2,"question":"Who may need a TRV or eTA besides work permit approval?","options":["Workers who require a travel document to board and enter Canada","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Travel authorization and work authorization are related but separate."},{"level":2,"question":"What should an employer avoid in LMIA recruitment?","options":["Unfairly tailoring requirements to exclude qualified Canadians","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Artificially restrictive recruitment can undermine the labour market test."},{"level":2,"question":"What is a compliance inspection?","options":["A review of whether the employer met program obligations","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employers can be inspected for wages, duties, conditions, and records."},{"level":2,"question":"Which proof can show the worker is qualified?","options":["Resume, credentials, licences, and reference letters","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"The worker must often show they can perform the job."},{"level":2,"question":"Why check regulated occupations?","options":["Provincial licensing may be required","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Some jobs require registration before the worker can legally perform them."},{"level":2,"question":"What is biometrics'' role in work permits?","options":["Identity and security screening","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Many applicants must provide fingerprints and a photo unless exempt."},{"level":2,"question":"Which job change should be addressed before work continues?","options":["A substantial change in employer, duties, wage, or location","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Material changes can make the current permit inaccurate."},{"level":2,"question":"What is maintained status for a work permit extension?","options":["Temporary status that may continue after a timely extension application","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Maintained status usually preserves prior conditions while a decision is pending."},{"level":2,"question":"What is needed to move from one closed employer to another?","options":["A new work permit supported by the new employer''s authorization basis","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Changing closed employers normally requires a new authorization."},{"level":2,"question":"What should an LMIA-exempt explanation identify?","options":["The exemption code and evidence meeting its criteria","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"LMIA-exempt categories require specific legal criteria."},{"level":2,"question":"Why does the employment contract matter?","options":["It confirms duties, wage, hours, benefits, and location","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Contracts help prove offer terms and employer obligations."},{"level":2,"question":"What is the usual sequence for TFWP work permits?","options":["Employer obtains LMIA, then worker applies for the permit","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A positive LMIA is usually needed before the worker''s application."},{"level":3,"question":"What is the risk of working for a different employer on a closed permit?","options":["Unauthorized work and future admissibility concerns","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Closed permits authorize only the listed employment."},{"level":3,"question":"Why can employer compliance history affect future hiring?","options":["Non-compliant employers may face bans, penalties, or refusal risk","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Program compliance findings can affect future foreign-worker hiring."},{"level":3,"question":"What is the issue with paying less than the approved wage?","options":["It may breach employer obligations and permit conditions","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employers must generally provide the approved wages and conditions."},{"level":3,"question":"When is a duty change problematic?","options":["When duties no longer match the approved NOC or offer","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Material duty changes can require a new assessment."},{"level":3,"question":"Why is NOC misclassification risky?","options":["It can undermine LMIA, work permit, and later PR claims","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"NOC affects eligibility, wages, duties, and immigration alignment."},{"level":3,"question":"What is a risk in owner-operator style LMIA cases?","options":["Questions about genuineness, control, and labour market need","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Ownership-linked employment requires careful evidence."},{"level":3,"question":"What weakens an LMIA recruitment file?","options":["Rejecting qualified Canadians without documented job-related reasons","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Recruitment decisions should be legitimate and documented."},{"level":3,"question":"Why are layoffs near an LMIA application sensitive?","options":["They may raise concerns about labour need and impact on Canadians","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Recent layoffs can affect whether hiring a foreign worker is justified."},{"level":3,"question":"What is the significance of LMIA expiry?","options":["The worker must use it for a permit application within validity","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"An LMIA has a validity period for supporting an application."},{"level":3,"question":"Which issue can trigger inadmissibility concerns?","options":["False documents or undisclosed immigration history","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Misrepresentation can have serious consequences."},{"level":3,"question":"Why distinguish business visitor from worker?","options":["Some activities require a work permit while limited business activities may not","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Misclassifying work as business visits can create unauthorized work."},{"level":3,"question":"What is advanced in intra-company transferee cases?","options":["Proving corporate relationship and specialized knowledge or executive capacity","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"ICT cases require evidence about both companies and the worker''s role."},{"level":3,"question":"Why can start-up employers face scrutiny?","options":["They must prove they can genuinely employ and pay the worker","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"New businesses may need stronger operational and financial evidence."},{"level":3,"question":"What is risky about generic NOC job descriptions?","options":["They may fail to prove the actual job is genuine","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Applications should describe real duties, not copied text alone."},{"level":3,"question":"What is central in significant benefit IMP cases?","options":["Evidence of important social, cultural, or economic benefit","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Significant benefit exemptions require persuasive Canada-benefit evidence."},{"level":3,"question":"Why can unauthorized work harm later Express Entry plans?","options":["It may not count and can raise compliance issues","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Unauthorized experience can affect both eligibility and credibility."},{"level":3,"question":"How should a procedural fairness letter be handled?","options":["Address the concerns with evidence before the deadline","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"A PFL is a chance to respond before possible refusal."},{"level":3,"question":"Why keep employer records after the worker starts?","options":["They may be needed during compliance inspections","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Employer obligations continue after permit issuance."},{"level":3,"question":"Which change may require a fresh LMIA or offer submission?","options":["A material change to employer, duties, wage, or location","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Material changes can require new authorization."},{"level":3,"question":"Why do provincial employment standards matter?","options":["Employer obligations include applicable workplace laws","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Foreign-worker programs do not override workplace standards."},{"level":3,"question":"What is a risk of inflated recruitment requirements?","options":["They may appear designed to exclude local applicants","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Requirements should be reasonable and necessary."},{"level":3,"question":"Why avoid starting before the permit is issued or activated?","options":["Approval steps may not yet equal legal authorization to work","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Work can begin only when the worker has proper authorization."},{"level":3,"question":"What supports a reciprocal employment exemption?","options":["Evidence of balanced opportunities for Canadians abroad","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Reciprocity relies on mutual benefit."},{"level":3,"question":"What can complicate a work permit extension?","options":["Expired passport, changed duties, or employer non-compliance","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Extensions depend on both worker and employer circumstances."},{"level":3,"question":"What is safest when work conditions no longer match the permit?","options":["Obtain proper authorization before continuing changed work","A regular visitor record","A provincial health card","A permanent resident visa"],"correctIndex":0,"explanation":"Correct authorization reduces compliance risk."}],"donts":{"dos":["Verify LMIA vs exempt category","Confirm employer legitimacy","Align NOC with job duties","Track LMIA and IRCC timelines","Complete medical/biometrics promptly"],"donts":["Do not guarantee work permit","Do not proceed with fraudulent employers","Do not submit IRCC before positive LMIA when required","Do not misclassify NOC/TEER","Do not hide unauthorized work history"],"mistakes":["LMIA advertising non-compliance","Wage below prevailing median","Employer on non-compliant list","Wrong exemption code claimed","Medical deadline missed"]},"sampleDocs":[{"title":"Sample passport bio page (mock)","description":"Show clients which pages to scan — MRZ visible, no glare, full spread.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample job offer / LMIA letter (mock)","description":"Employer name, role, wage, and LMIA number where required.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample employer support letter (mock)","description":"Confirms position is genuine and client meets role requirements.","mimeType":"application/pdf","docKind":"employment"},{"title":"Sample qualifications proof (mock)","description":"Degree and experience matching NOC / SOC role.","mimeType":"application/pdf","docKind":"academic"},{"title":"Sample bank statement (mock)","description":"6-month statement with name, account number, and closing balance — explain seasoning.","mimeType":"application/pdf","docKind":"financial"}],"navBucket":"immigration","workingRights":{"applicant":{"summary":"Employer-specific or open work permits authorize work per conditions on the permit (employer, occupation, location, expiry).","details":["LMIA-exempt streams (IEC, PGWP, BOWP, IEC, intra-company) have specific rules.","PR applicants with maintained status may qualify for BOWP."],"restrictions":["Working outside permit conditions is unauthorized employment"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship/services/work-canada.html","lastVerified":"Jun 2026"},"spouse":{"summary":"Spouse/partner of skilled worker or PR applicant often eligible for open work permit (SOWP) during processing or after PR stage.","details":["PNP nominations may include employment restrictions affecting open permits — verify nomination letter."],"restrictions":[],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","lastVerified":"Jun 2026"}},"fullCostBreakdown":{"title":"Full cost breakdown — Canada – Work Permit (LMIA & LMIA-Exempt)","currency":"CAD","lastVerified":"Jun 2026","disclaimer":"Indicative costs for counselor discussions only. Government fees, tuition, and living amounts change — verify on official websites before quoting clients. Exchange rates affect INR equivalents.","sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","sections":[{"id":"fees","label":"Government & visa fees","items":[{"label":"PR / work permit fees","range":"155–650","notes":"Varies by stream","currency":"CAD","applicable":true},{"label":"Biometrics","amount":85,"currency":"CAD","applicable":true},{"label":"Medical & police","range":"Varies","notes":"Third party","currency":"CAD","applicable":true}]},{"id":"tuition","label":"Tuition & education costs","items":[{"label":"Credential recognition / skills assessment","range":"Varies","notes":"If required for license","currency":"CAD","applicable":true}]},{"id":"living","label":"Living costs","items":[{"label":"Living funds (IRCC guideline, 1 person)","amount":20635,"unit":"per year","notes":"Outside Quebec","currency":"CAD"},{"label":"Accommodation","range":"700–1,400","unit":"per month","currency":"CAD"},{"label":"Food & personal","range":"300–550","unit":"per month","currency":"CAD"}]},{"id":"misc","label":"Miscellaneous","items":[{"label":"Future Link consultancy fee","range":"See Fees tab","not